fn solve(nums: Vec<i64>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    let n = nums.len();
    let mut ans = Vec::new();

    for query in queries {
        let l = query[0] as usize;
        let r = query[1] as usize;
        let threshold = query[2] as usize;

        let mut freq = std::collections::HashMap::new();
        for i in l..=r {
            *freq.entry(nums[i]).or_insert(0) += 1;
        }

        let mut max_freq = 0;
        let mut result = -1;

        for (&num, &count) in &freq {
            if count >= threshold && count > max_freq {
                max_freq = count;
                result = num;
            } else if count >= threshold && count == max_freq {
                if num < result {
                    result = num;
                }
            }
        }

        ans.push(result);
    }

    ans
}
